import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import CloseIcon from '@mui/icons-material/Close';
import GoogleIcon from '@mui/icons-material/Google';
import Avatar from '@mui/material/Avatar';
import Box from '@mui/material/Box';
import Button from '@mui/material/Button';
import Card from '@mui/material/Card';
import Checkbox from '@mui/material/Checkbox';
import Dialog from '@mui/material/Dialog';
import DialogContent from '@mui/material/DialogContent';
import IconButton from '@mui/material/IconButton';
import ListItem from '@mui/material/ListItem';
import ListItemText from '@mui/material/ListItemText';
import Typography from '@mui/material/Typography';
import { useTranslations } from 'next-intl';

// Note: If GoogleIcon is not available in mui/icons-material, use a custom SVG or just 'G' text. 
// Assuming it exists or I'll use a placeholder.

interface ConnectGoogleModalProps {
    open: boolean;
    onClose: () => void;
    onConnect: () => void;
}

const ConnectGoogleModal = ({ open, onClose, onConnect }: ConnectGoogleModalProps) => {
    const t = useTranslations('locations.ReviewSources.googleModal');
    const tc = useTranslations('common');

    // Hardcoded steps for display matching Image 0
    const steps = [
        { id: 1, title: t('step1Title'), description: t('step1Desc') },
        { id: 2, title: t('step2Title'), description: t('step2Desc') },
        { id: 3, title: t('step3Title'), description: t('step3Desc') }
    ];

    const permissions = [
        t('permission1'),
        t('permission2'),
        t('permission3')
    ];

    return (
        <Dialog 
            open={open} 
            onClose={onClose} 
            maxWidth="md" 
            fullWidth
            PaperProps={{
                sx: { 
                    borderRadius: 3,
                    bgcolor: 'background.paper',
                    backgroundImage: 'none' // Remove default elevation gradient
                }
            }}
        >
             <Box sx={{ position: 'relative', p: 1 }}>
                <IconButton onClick={onClose} sx={{ position: 'absolute', right: 8, top: 8 }}>
                    <CloseIcon />
                </IconButton>

                <Box sx={{ display: 'flex', alignItems: 'center', gap: 2, p: 3, pb: 2 }}>
                    <Avatar sx={{ bgcolor: 'white', border: '1px solid #E0E0E0' }}>
                        <GoogleIcon sx={{ color: '#4285F4' }} />
                    </Avatar>
                    <Box>
                        <Typography variant="h5" fontWeight="bold">{t('title')}</Typography>
                        <Typography variant="body2" color="text.secondary">{t('subtitle')}</Typography>
                    </Box>
                </Box>
            </Box>

            <DialogContent sx={{ px: 4, pb: 4 }}>
                {/* Steps Section */}
                <Box sx={{ mb: 4 }}>
                     {steps.map((step) => (
                         <Box key={step.id} sx={{ display: 'flex', gap: 2, mb: 3 }}>
                             <Avatar 
                                sx={{ 
                                    bgcolor: 'warning.main', // Using warning logic matching Image 0 orange/gold
                                    color: 'white',
                                    width: 32, 
                                    height: 32,
                                    fontSize: '0.875rem',
                                    fontWeight: 'bold'
                                }}
                            >
                                {step.id}
                            </Avatar>
                            <Box>
                                <Typography variant="subtitle1" fontWeight="bold">{step.title}</Typography>
                                <Typography variant="body2" color="text.secondary">{step.description}</Typography>
                            </Box>
                         </Box>
                     ))}
                </Box>

                {/* Permissions Section */}
                <Card variant="outlined" sx={{ p: 2.5, mb: 4, bgcolor: 'background.default', border: '1px solid', borderColor: 'divider' }}>
                     <Box sx={{ display: 'flex', alignItems: 'center', gap: 1.5, mb: 2 }}>
                         {/* Purple shield icon substitute */}
                         <CheckCircleIcon color="secondary" /> 
                         <Typography variant="h6">{t('permissionsTitle')}</Typography>
                     </Box>
                     {permissions.map((perm, idx) => (
                         <Box key={idx} sx={{ display: 'flex', alignItems: 'center', gap: 1.5, mb: 1 }}>
                             <CheckCircleIcon color="success" fontSize="small" />
                             <Typography variant="body2">{perm}</Typography>
                         </Box>
                     ))}
                </Card>

                 <Box sx={{ bgcolor: 'background.default', p: 2, borderRadius: 1, display: 'flex', justifyContent: 'space-between', alignItems: 'center', mt: 4 }}>
                    <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                        <Typography variant="caption" color="text.secondary">{t('secure')}</Typography>
                    </Box>
                    <Box sx={{ display: 'flex', gap: 2 }}>
                        <Button onClick={onClose} variant="text" color="inherit">{tc('common.cancel')}</Button>
                        <Button onClick={onConnect} variant="contained" color="primary" size="large" sx={{ fontWeight: 'bold' }}>
                            {t('connectBtn')}
                        </Button>
                    </Box>
                 </Box>

            </DialogContent>
        </Dialog>
    );
};

export default ConnectGoogleModal;

import type { ReactNode } from 'react'
import { useState, useEffect, useCallback } from 'react'
import { useParams, useRouter, useSearchParams } from 'next/navigation'
import Box from '@mui/material/Box'
import Button from '@mui/material/Button'
import Card from '@mui/material/Card'
import CircularProgress from '@mui/material/CircularProgress'
import Divider from '@mui/material/Divider'
import Stack from '@mui/material/Stack'
import Typography from '@mui/material/Typography'
import IconButton from '@mui/material/IconButton'
import Snackbar from '@mui/material/Snackbar'
import Link from '@mui/material/Link'
import Tooltip from '@mui/material/Tooltip'

// Icons
import AddCircleOutlineIcon from '@mui/icons-material/AddCircleOutline'
import CheckCircleIcon from '@mui/icons-material/CheckCircle'
import BlockIcon from '@mui/icons-material/Block'
import RefreshIcon from '@mui/icons-material/Refresh'
import LinkOffIcon from '@mui/icons-material/LinkOff'
import InfoOutlinedIcon from '@mui/icons-material/InfoOutlined'
import GoogleIcon from '@mui/icons-material/Google'

import { useTranslations } from 'next-intl'
import apiClient from '@/lib/apiClient'
import ConnectGoogleModal from './ConnectGoogleModal'
import LocationSelectorModal from './LocationSelectorModal'

interface ConnectionStatus {
    connected: boolean
    status?: 'active' | 'error' | 'disconnected'
    integrationId?: string
    gbpLocationTitle?: string
    gbpLocationName?: string
    connectedAt?: string
}

export default function IntegrationsDashboard() {
    const t = useTranslations('locations.ReviewSources') // Reusing translations for now
    const params = useParams()
    const searchParams = useSearchParams()
    const router = useRouter()
    const { id: locationId } = params

    const [status, setStatus] = useState<ConnectionStatus | null>(null)
    const [loading, setLoading] = useState(true)
    const [isConnectModalOpen, setIsConnectModalOpen] = useState(false)
    
    // Auth flow states
    const pendingGoogleId = searchParams.get('pending_google')
    const googleError = searchParams.get('google_error')
    
    const [isSelectorOpen, setIsSelectorOpen] = useState(!!pendingGoogleId)
    const [snackbarMsg, setSnackbarMsg] = useState<string | null>(null)

    const fetchStatus = useCallback(async () => {
        if (!locationId) return

        try {
            setLoading(true)
            const res = await apiClient.get(`/auth/google/status/${locationId}`)

            setStatus(res.data.data)
        } catch (error) {
            console.error('Failed to fetch integration status:', error)
        } finally {
            setLoading(false)
        }
    }, [locationId])

    useEffect(() => {
        fetchStatus()
    }, [fetchStatus])

    useEffect(() => {
        if (googleError) {
            let msg = t('errors.default')

            if (googleError === 'access_denied') msg = t('errors.accessDenied')
            else if (googleError === 'no_accounts') msg = t('errors.noAccounts')
            else if (googleError === 'no_locations') msg = t('errors.noLocations')
            else if (googleError === 'session_expired') msg = t('errors.sessionExpired')

            setSnackbarMsg(msg)

            // Strip from URL after showing
            const newUrl = new URL(window.location.href)

            newUrl.searchParams.delete('google_error')
            router.replace(newUrl.pathname + newUrl.search)
        }

        if (pendingGoogleId) {
            setIsSelectorOpen(true)

            // Strip pending ID
            const newUrl = new URL(window.location.href)

            newUrl.searchParams.delete('pending_google')
            router.replace(newUrl.pathname + newUrl.search)
        }
    }, [googleError, pendingGoogleId, router, t])

    const handleConnectGoogle = async () => {
        try {
            const res = await apiClient.get(`/auth/google/connect?locationId=${locationId}`)

            if (res.data?.data?.url) {
                window.location.href = res.data.data.url
            } else {
                setSnackbarMsg('Failed to generate connection link.')
            }
        } catch (error) {
            setSnackbarMsg('An error occurred. Please try again.')
        }
    }

    const handleDisconnect = async () => {
        if (!confirm('Are you sure you want to disconnect this location? Features relying on this connection will stop working.')) return

        try {
            setLoading(true)
            await apiClient.post(`/auth/google/disconnect/${locationId}`)
            await fetchStatus()
            setSnackbarMsg('Google Business Profile disconnected.')
        } catch (error) {
            setSnackbarMsg('Failed to disconnect. Please try again.')
            setLoading(false)
        }
    }

    if (loading) {
        return (
            <Box sx={{ display: 'flex', justifyContent: 'center', p: 4 }}>
                <CircularProgress />
            </Box>
        )
    }

    return (
        <Box sx={{ p: { xs: 2, sm: 4 } }}>
            <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 4 }}>
                <Typography variant="h5" fontWeight="bold">Connected Platforms</Typography>
            </Box>
            
            <Typography variant="body1" color="text.secondary" sx={{ mb: 4 }}>
                Connect your location to external platforms like Google Business Profile. 
                Once connected, these integrations power features like Review Syncing and GBP Rocket across the platform.
            </Typography>

            <Card sx={{ p: 4, borderRadius: 2, display: 'flex', alignItems: 'flex-start', border: status?.connected ? '1px solid #4CAF50' : 'none' }}>
                <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'center', width: 64, height: 64, borderRadius: '50%', bgcolor: 'background.default', mr: 3 }}>
                    <GoogleIcon fontSize="large" sx={{ color: '#4285F4' }} />
                </Box>
                <Box sx={{ flexGrow: 1 }}>
                    <Typography variant="h6" fontWeight="bold" sx={{ mb: 1 }}>Google Business Profile</Typography>
                    
                    {status?.connected && status.status === 'active' ? (
                        <>
                            <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 2 }}>
                                <CheckCircleIcon color="success" fontSize="small" />
                                <Typography variant="body2" color="success.main" fontWeight="bold">Connected</Typography>
                                <Typography variant="body2" color="text.secondary">
                                    to <strong>{status.gbpLocationTitle || status.gbpLocationName}</strong>
                                </Typography>
                            </Box>
                            <Typography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
                                Your connection is active. Features like Review Sync and Auto-Replies can use this connection.
                            </Typography>
                            <Button 
                                variant="outlined" 
                                color="error" 
                                size="small"
                                startIcon={<LinkOffIcon />}
                                onClick={handleDisconnect}
                            >
                                Disconnect
                            </Button>
                        </>
                    ) : status?.connected && status.status === 'error' ? (
                        <>
                            <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 2 }}>
                                <BlockIcon color="error" fontSize="small" />
                                <Typography variant="body2" color="error.main" fontWeight="bold">Connection Error</Typography>
                            </Box>
                            <Typography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
                                We lost access to your Google account. Please reconnect to restore functionality.
                            </Typography>
                            <Button variant="contained" color="primary" onClick={() => setIsConnectModalOpen(true)}>
                                Reconnect Google
                            </Button>
                        </>
                    ) : (
                        <>
                            <Typography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
                                Connect to Google Business Profile to enable automatic review syncing, AI response generation, and GBP posting.
                            </Typography>
                            <Button 
                                variant="contained" 
                                color="primary" 
                                startIcon={<AddCircleOutlineIcon />}
                                onClick={() => setIsConnectModalOpen(true)}
                            >
                                Connect Google
                            </Button>
                        </>
                    )}
                </Box>
            </Card>

            <ConnectGoogleModal 
                open={isConnectModalOpen} 
                onClose={() => setIsConnectModalOpen(false)} 
                onConnect={handleConnectGoogle}
            />

            <LocationSelectorModal 
                open={isSelectorOpen}
                pendingId={pendingGoogleId || ''}
                onClose={() => setIsSelectorOpen(false)}
                onSuccess={() => {
                    setIsSelectorOpen(false)
                    setSnackbarMsg('Successfully connected to Google Business Profile!')
                    fetchStatus()
                }}
            />

            <Snackbar
                open={!!snackbarMsg}
                autoHideDuration={6000}
                onClose={() => setSnackbarMsg(null)}
                message={snackbarMsg}
            />
        </Box>
    )
}

/* eslint-disable import/no-unresolved */
import { useState, useEffect, useCallback } from 'react';

import { useParams, useSearchParams, useRouter } from 'next/navigation';

import { useTranslations } from 'next-intl';

import { Box, Button, Card, CardContent, Grid, LinearProgress, Typography, Dialog, Snackbar, Alert, Skeleton } from '@mui/material';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import ScheduleIcon from '@mui/icons-material/Schedule';
import StarIcon from '@mui/icons-material/Star';
import SyncIcon from '@mui/icons-material/Sync';
import GoogleIcon from '@mui/icons-material/Google';


import apiClient from '@/lib/apiClient';

import ConnectionSuccessView from './ConnectionSuccessView';
import ConnectedSourceCard from './ConnectedSourceCard';
import AvailableSourceCard from './AvailableSourceCard';

export interface ReviewSource {
    id: string;
    platform: string;
    status: string;
    locationId: string;
}

interface ReviewStats {
    totalReviews: number;
    averageRating: number;
}

import { SERVICES_CONFIG } from '@/configs/services';

const REVIEWS_API_URL = SERVICES_CONFIG.review.url;

const ReviewSourcesDashboard = () => {
    const t = useTranslations('locations.ReviewSources');
    const params = useParams();
    const searchParams = useSearchParams();
    const router = useRouter();
    const { id: locationId } = params;

    const [modalOpen, setModalOpen] = useState(false);
    const [pendingId, setPendingId] = useState<string | null>(null);
    const [view, setView] = useState<'dashboard' | 'success'>('dashboard');
    const [sources, setSources] = useState<ReviewSource[]>([]);
    const [stats, setStats] = useState<ReviewStats | null>(null);
    const [loading, setLoading] = useState(true);
    const [syncing, setSyncing] = useState(false);

    const [snackbar, setSnackbar] = useState<{ open: boolean; message: string; severity: 'success' | 'error' | 'info' }>({
        open: false,
        message: '',
        severity: 'info'
    });

    // Check for success or pending params on mount
    useEffect(() => {
        const connected = searchParams.get('google_connected');
        const pending = searchParams.get('pending_google');
        const error = searchParams.get('google_error');

        if (connected === 'true') {
            setView('success');
            const newParams = new URLSearchParams(searchParams.toString());

            newParams.delete('google_connected');
            router.replace(`?${newParams.toString()}`);
            setSnackbar({ open: true, message: t('sourceConnected'), severity: 'success' });
        } else if (pending) {
            setPendingId(pending);
            const newParams = new URLSearchParams(searchParams.toString());

            newParams.delete('pending_google');
            router.replace(`?${newParams.toString()}`);
        } else if (error) {
            let errorMsg = t('failedToConnect');

            // Map specific errors to translated messages
            if (error === 'access_denied') errorMsg = t('errors.accessDenied');
            else if (error === 'no_accounts') errorMsg = t('errors.noAccounts');
            else if (error === 'no_locations') errorMsg = t('errors.noLocations');
            else if (error === 'session_expired') errorMsg = t('errors.sessionExpired');
            else if (error === 'invalid_callback' || error === 'invalid_state') errorMsg = t('errors.invalidCallback');
            else if (error === 'server_error') errorMsg = t('errors.serverError');

            setSnackbar({ open: true, message: errorMsg, severity: 'error' });

            const newParams = new URLSearchParams(searchParams.toString());

            newParams.delete('google_error');
            router.replace(`?${newParams.toString()}`);
        }
    }, [searchParams, router, t]);

    const fetchData = useCallback(async () => {
        if (!locationId) return;

        try {
            setLoading(true);

            // Use apiClient (auto-unwraps data field)
            const [sourcesRes, statsRes] = await Promise.all([
                apiClient.get<ReviewSource[]>(`${REVIEWS_API_URL}/locations/${locationId}/sources`),
                apiClient.get<ReviewStats>(`${REVIEWS_API_URL}/locations/${locationId}/stats`)
            ]);

            if (sourcesRes.data) setSources(sourcesRes.data);
            if (statsRes.data) setStats(statsRes.data);

        } catch (error) {
            console.error('Failed to fetch dashboard data', error);
            setSnackbar({ open: true, message: t('failedToLoad'), severity: 'error' });
        } finally {
            setLoading(false);
        }
    }, [locationId, t]);

    useEffect(() => {
        fetchData();
    }, [fetchData]);

    const [googleConnected, setGoogleConnected] = useState(false);

    const checkGoogleStatus = useCallback(async () => {
        if (!locationId) return;

        try {
            const res = await apiClient.get(`/auth/google/status/${locationId}`);

            setGoogleConnected(res.data?.data?.connected === true);
        } catch (error) {
            console.error('Failed to check google status', error);
        }
    }, [locationId]);

    useEffect(() => {
        checkGoogleStatus();
    }, [checkGoogleStatus]);

    const handleEnableGoogleSync = async () => {
        if (!locationId) return;

        try {
            setLoading(true);
            await apiClient.post(`${REVIEWS_API_URL}/locations/${locationId}/enable-google-sync`);
            setSnackbar({ open: true, message: 'Google Review Sync Enabled', severity: 'success' });
            fetchData();
        } catch (error) {
            console.error('Failed to enable sync', error);
            setSnackbar({ open: true, message: 'Failed to enable Google Sync', severity: 'error' });
            setLoading(false);
        }
    };

    const handleDisconnect = async (id: string) => {
        try {
            await apiClient.delete(`${REVIEWS_API_URL}/sources/${id}`);
            setSnackbar({ open: true, message: t('sourceDisconnected'), severity: 'success' });
            fetchData();
        } catch (error) {
            console.error('Failed to disconnect', error);
            setSnackbar({ open: true, message: t('failedToDisconnect'), severity: 'error' });
        }
    };

    const handleSyncAll = async () => {
        if (!locationId) return;

        try {
            setSyncing(true);
            setSnackbar({ open: true, message: t('syncStarted'), severity: 'info' });
            await apiClient.post(`${REVIEWS_API_URL}/locations/${locationId}/sync`);
            setSnackbar({ open: true, message: t('syncCompletedMsg'), severity: 'success' });
            fetchData();
        } catch (error) {
            console.error('Sync failed', error);
            setSnackbar({ open: true, message: t('syncFailed'), severity: 'error' });
        } finally {
            setSyncing(false);
        }
    };

    const handleGoToDashboard = () => {
        setView('dashboard');
    };

    const handleCloseSnackbar = () => {
        setSnackbar({ ...snackbar, open: false });
    };

    return (
        <Box>
            <Snackbar
                open={snackbar.open}
                autoHideDuration={6000}
                onClose={handleCloseSnackbar}
                anchorOrigin={{ vertical: 'bottom', horizontal: 'right' }}
            >
                <Alert onClose={handleCloseSnackbar} severity={snackbar.severity} sx={{ width: '100%' }}>
                    {snackbar.message}
                </Alert>
            </Snackbar>



            <Dialog
                open={view === 'success'}
                onClose={handleGoToDashboard}
                maxWidth="sm"
                fullWidth
            >
                <ConnectionSuccessView onGoToDashboard={handleGoToDashboard} onViewLogs={handleGoToDashboard} />
            </Dialog>

            {/* Header */}
            <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 3 }}>
                <Box>
                    <Typography variant="h4" fontWeight="bold">{t('title')}</Typography>
                    <Typography variant="body2" color="text.secondary">{t('subtitle')}</Typography>
                </Box>
                <Button
                    variant="contained"
                    color="warning"
                    startIcon={<SyncIcon />}
                    onClick={handleSyncAll}
                    disabled={syncing || loading}
                >
                    {syncing ? t('syncing') : t('syncAllNow')}
                </Button>
            </Box>

            {/* Summary Cards */}
            <Grid container spacing={3} sx={{ mb: 4 }}>
                <Grid size={{ xs: 12, md: 4 }}>
                    <Card sx={{ bgcolor: 'background.paper', height: '100%' }}>
                        <CardContent sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                            <Box>
                                <Typography variant="caption" color="text.secondary">{t('connectedSources')}</Typography>
                                {loading ? <Skeleton variant="rectangular" width={40} height={40} sx={{ my: 1 }} /> : (
                                    <Typography variant="h3" fontWeight="bold" sx={{ my: 1 }}>{sources.length}</Typography>
                                )}
                                <Typography variant="caption" color="text.secondary">
                                    {loading ? <Skeleton width={100} /> : `${sources.length > 0 ? t('activeSources') : t('noSourcesConnected')}`}
                                </Typography>
                            </Box>
                            <Box sx={{ p: 1, bgcolor: 'primary.main', borderRadius: 2, color: 'primary.contrastText' }}>
                                <SyncIcon />
                            </Box>
                        </CardContent>
                    </Card>
                </Grid>
                <Grid size={{ xs: 12, md: 4 }}>
                    <Card sx={{ bgcolor: 'background.paper', height: '100%' }}>
                        <CardContent sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                            <Box>
                                <Typography variant="caption" color="text.secondary">{t('totalReviews')}</Typography>
                                {loading ? <Skeleton variant="rectangular" width={60} height={40} sx={{ my: 1 }} /> : (
                                    <Typography variant="h3" fontWeight="bold" sx={{ my: 1 }}>{stats?.totalReviews || 0}</Typography>
                                )}
                                <Typography variant="caption" color="text.secondary">
                                    {loading ? <Skeleton width={120} /> : t('averageRating', { rating: stats?.averageRating || 0 })}
                                </Typography>
                            </Box>
                            <Box sx={{ p: 1, bgcolor: 'success.main', borderRadius: 2, color: 'success.contrastText' }}>
                                <StarIcon />
                            </Box>
                        </CardContent>
                    </Card>
                </Grid>
                <Grid size={{ xs: 12, md: 4 }}>
                    <Card sx={{ bgcolor: 'background.paper', height: '100%' }}>
                        <CardContent sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                            <Box>
                                <Typography variant="caption" color="text.secondary">{t('syncStatus')}</Typography>
                                {loading ? <Skeleton variant="rectangular" width={80} height={40} sx={{ my: 1 }} /> : (
                                    <Typography variant="h3" fontWeight="bold" sx={{ my: 1 }}>{sources.length > 0 ? t('healthy') : t('inactive')}</Typography>
                                )}
                                <Typography variant="caption" color="text.secondary">
                                    {loading ? <Skeleton width={140} /> : (sources.length > 0 ? t('syncHealthy') : t('connectToSync'))}
                                </Typography>
                            </Box>
                            <Box sx={{ p: 1, bgcolor: 'secondary.main', borderRadius: 2, color: 'secondary.contrastText' }}>
                                <CheckCircleIcon />
                            </Box>
                        </CardContent>
                    </Card>
                </Grid>
            </Grid>

            <Grid container spacing={3}>
                {/* Connected Sources List */}
                <Grid size={{ xs: 12, md: 8 }}>
                    <Typography variant="h6" sx={{ mb: 2 }}>{t('connectedSources')}</Typography>

                    {loading ? (
                        <>
                            <Skeleton variant="rectangular" height={100} sx={{ mb: 2, borderRadius: 2 }} />
                            <Skeleton variant="rectangular" height={100} sx={{ mb: 2, borderRadius: 2 }} />
                        </>
                    ) : (
                        sources.length > 0 ? (
                            sources.map(source => (
                                <ConnectedSourceCard
                                    key={source.id}
                                    source={source}
                                    onDisconnect={handleDisconnect}
                                    onConfigure={() => setSnackbar({ open: true, message: t('configurationComingSoon'), severity: 'info' })}
                                />
                            ))
                        ) : (
                            <Typography color="text.secondary" sx={{ mb: 4 }}>{t('noSourcesYet')}</Typography>
                        )
                    )}

                    <Typography variant="h6" sx={{ mb: 2 }}>{t('availableSources')}</Typography>

                    {/* Filter out already connected specific platforms? For MVP, Google is unique. */}
                    {!sources.some(s => s.platform === 'google') && (
                        <Card sx={{ mb: 2, border: '1px solid', borderColor: 'divider', bgcolor: 'background.paper' }}>
                            <CardContent sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                <Box sx={{ display: 'flex', gap: 2, alignItems: 'center' }}>
                                    <Box sx={{ p: 1.5, bgcolor: 'action.hover', borderRadius: 2 }}><GoogleIcon color="info" /></Box>
                                    <Box>
                                        <Typography variant="subtitle1" fontWeight="bold">Google Business Profile</Typography>
                                        <Typography variant="caption" color="text.secondary">
                                            {googleConnected 
                                                ? "Google is connected. Click Enable to start syncing reviews."
                                                : "Go to the Integrations tab to connect your Google account."}
                                        </Typography>
                                    </Box>
                                </Box>
                                <Button 
                                    variant="contained" 
                                    color="primary" 
                                    onClick={googleConnected ? handleEnableGoogleSync : () => router.push(`/admin/locations/${locationId}?tab=integrations`)}

                                    // Make button say "Enable Sync" or "Go to Integrations"
                                >
                                    {googleConnected ? "Enable Sync" : "Go to Integrations"}
                                </Button>
                            </CardContent>
                        </Card>
                    )}

                    <AvailableSourceCard platform="facebook" disabled />
                    <AvailableSourceCard platform="trustpilot" disabled />
                    <AvailableSourceCard platform="yelp" disabled />

                </Grid>

                {/* Sidebar */}
                <Grid size={{ xs: 12, md: 4 }}>
                    <Card sx={{ mb: 3, bgcolor: 'background.paper' }}>
                        <CardContent>
                            <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 2 }}>
                                <ScheduleIcon color="secondary" />
                                <Typography variant="h6">{t('syncStatus')}</Typography>
                            </Box>

                            <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 1 }}>
                                <Typography variant="caption" color="text.secondary">{t('nextScheduledSync')}</Typography>
                                <Typography variant="caption" fontWeight="bold">{t('inHours', { hours: 4 })}</Typography>
                            </Box>
                            <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 1 }}>
                                <Typography variant="caption" color="text.secondary">{t('syncFrequency')}</Typography>
                                <Typography variant="caption" fontWeight="bold">{t('dailyAt', { time: t('googleModal.mockTime') })}</Typography>
                            </Box>
                            <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 3 }}>
                                <Typography variant="caption" color="text.secondary">{t('lastSyncDuration')}</Typography>
                                <Typography variant="caption" fontWeight="bold">{t('googleModal.mockDurationValue')}</Typography>
                            </Box>

                            <Typography variant="caption" color="text.secondary" gutterBottom>{t('currentSyncProgress')}</Typography>
                            <LinearProgress variant="determinate" value={syncing ? 30 : 0} sx={{ bgcolor: 'action.hover', '& .MuiLinearProgress-bar': { bgcolor: 'warning.main' } }} />
                        </CardContent>
                    </Card>

                    <Card>
                        <CardContent>
                            <Typography variant="h6" sx={{ mb: 2 }}>{t('recentActivity')}</Typography>
                            <Box sx={{ display: 'flex', gap: 2, mb: 3 }}>
                                <Box sx={{ p: 0.5, bgcolor: 'success.main', borderRadius: 1, height: 'fit-content', color: 'success.contrastText' }}>
                                    <CheckCircleIcon fontSize="small" color="inherit" />
                                </Box>
                                <Box>
                                    <Typography variant="body2" fontWeight="bold">{t('syncCompleted')}</Typography>
                                    <Typography variant="caption" color="text.secondary">{t('newReviews', { hours: 2, count: 23 })}</Typography>
                                </Box>
                            </Box>
                        </CardContent>
                    </Card>
                </Grid>
            </Grid>
        </Box>
    );
};

export default ReviewSourcesDashboard;
